class Solution:
    def solve(self, buildings: List[List[int]]) -> List[List[int]]:
        events = []
        for L, R, H in buildings:
            events.append((L, -H, R))
            events.append((R, 0, 0))
        events.sort()
        res = [[0, 0]]
        hp = [(0, float('inf'))]
        for x, h, r in events:
            if h < 0: heapq.heappush(hp, (h, r))
            while hp[0][1] <= x: heapq.heappop(hp)
            max_h = -hp[0][0]
            if res[-1][1] != max_h: res.append([x, max_h])
        return res[1:]

